func (g *Manager) createLocalConnection(parentCtx context.Context, port int, enableTLS bool) (conn *grpc.ClientConn, err error) {
	opts := make([]grpc.DialOption, 0, 2)

	if diag.DefaultGRPCMonitoring.IsEnabled() {
		opts = append(opts,
			grpc.WithUnaryInterceptor(diag.DefaultGRPCMonitoring.UnaryClientInterceptor()),
		)
	}

	if enableTLS {
		//nolint:gosec
		tlsConfig := &tls.Config{InsecureSkipVerify: true}
		tlsConfig.MinVersion = channel.AppChannelMinTLSVersion
		opts = append(opts, grpc.WithTransportCredentials(credentials.NewTLS(tlsConfig)))
	} else {
		opts = append(opts, grpc.WithTransportCredentials(insecure.NewCredentials()))
	}
	opts = append(opts, grpc.WithConnectParams(grpc.ConnectParams{
		Backoff:           backoff.DefaultConfig,
		MinConnectTimeout: 1 * time.Second,
	}))

	dialPrefix := GetDialAddressPrefix(g.mode)
	address := net.JoinHostPort(g.channelConfig.BaseAddress, strconv.Itoa(port))

	ctx, cancel := context.WithTimeout(parentCtx, dialTimeout)
	defer cancel()
	return grpc.DialContext(ctx, dialPrefix+address, opts...) //nolint:staticcheck
}

func appHTTPClient(connConfig config.AppConnectionConfig, globalConfig *config.Configuration, readBufferSize int) *http.Client {
	var transport http.RoundTripper

	if connConfig.Protocol == protocol.H2CProtocol {
		// Enable HTTP/2 Cleartext transport
		transport = &http2.Transport{
			AllowHTTP: true, // To enable using "http" as protocol
			DialTLS: func(network, addr string, _ *tls.Config) (net.Conn, error) {
				// Return the TCP socket without TLS
				return net.Dial(network, addr)
			},
			// TODO: This may not be exactly the same as "MaxResponseHeaderBytes" so check before enabling this
			// MaxHeaderListSize: uint32(a.runtimeConfig.readBufferSize),
		}
	} else {
		var tlsConfig *tls.Config
		if connConfig.Protocol == protocol.HTTPSProtocol {
			tlsConfig = &tls.Config{
				InsecureSkipVerify: true, //nolint:gosec
				MinVersion:         channel.AppChannelMinTLSVersion,
			}
		}

		ts := http.DefaultTransport.(*http.Transport).Clone()
		ts.ForceAttemptHTTP2 = false
		ts.TLSClientConfig = tlsConfig
		ts.ReadBufferSize = readBufferSize
		ts.MaxResponseHeaderBytes = int64(readBufferSize)
		ts.MaxConnsPerHost = 1024
		ts.MaxIdleConns = 64 // A local channel connects to a single host
		ts.MaxIdleConnsPerHost = 64
		transport = ts
	}

	// Initialize this property in the object, and then pass it to the HTTP channel and the actors runtime (for health checks)
	// We want to re-use the same client so TCP sockets can be re-used efficiently across everything that communicates with the app
	// This is especially useful if the app supports HTTP/2
	return &http.Client{
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}
}

func (a *DaprRuntime) blockUntilAppIsReady(ctx context.Context) error {
	if a.runtimeConfig.appConnectionConfig.Port <= 0 {
		return nil
	}

	log.Infof("application protocol: %s. waiting on port %v.  This will block until the app is listening on that port.", string(a.runtimeConfig.appConnectionConfig.Protocol), a.runtimeConfig.appConnectionConfig.Port)

	dialAddr := a.runtimeConfig.appConnectionConfig.ChannelAddress + ":" + strconv.Itoa(a.runtimeConfig.appConnectionConfig.Port)

	for {
		var (
			conn net.Conn
			err  error
		)
		dialer := &net.Dialer{
			Timeout: 500 * time.Millisecond,
		}
		if a.runtimeConfig.appConnectionConfig.Protocol.HasTLS() {
			conn, err = tls.DialWithDialer(dialer, "tcp", dialAddr, &tls.Config{
				InsecureSkipVerify: true, //nolint:gosec
			})
		} else {
			conn, err = dialer.DialContext(ctx, "tcp", dialAddr)
		}
		if err == nil && conn != nil {
			conn.Close()
			break
		}

		select {
		// Return
		case <-ctx.Done():
			return ctx.Err()
		// prevents overwhelming the OS with open connections
		case <-a.clock.After(time.Millisecond * 100):
		}
	}

	log.Infof("application discovered on port %v", a.runtimeConfig.appConnectionConfig.Port)

	return nil
}

func largeDataErrorServiceCall(w http.ResponseWriter, r *http.Request, isHTTP bool) {
	fmt.Println("Entering largeDataErrorServiceCall")

	// post
	url := fmt.Sprintf(
		"http://localhost:%s/v1.0/invoke/serviceinvocation-callee-0/method/posthandler",
		strconv.Itoa(daprHTTPPort))

	testSizes := []struct {
		size int
		name string
	}{
		{
			size: 1024 * 1024,
			name: "1MB",
		},
		{
			size: 1024*1024*3 - 454,
			name: "4MB",
		},
		{
			size: 1024*1024*3 + 10,
			name: "4MB+",
		},
		{
			size: 1024 * 1024 * 8,
			name: "8MB",
		},
	}

	results := make([]individualTestResult, len(testSizes))
	for i, test := range testSizes {
		var result individualTestResult
		result.TestCase = test.name

		body := make([]byte, test.size)
		jsonBody, _ := json.Marshal(body)
		fmt.Printf("largeDataErrorServiceCall %s - Request size: %d\n", test.name, len(jsonBody))

		if isHTTP {
			resp, err := httpClient.Post(sanitizeHTTPURL(url), jsonContentType, bytes.NewReader(jsonBody))
			result.CallSuccessful = !((resp != nil && resp.StatusCode != http.StatusOK) || err != nil)
			if resp != nil {
				// Drain before closing
				_, _ = io.Copy(io.Discard, resp.Body)
				resp.Body.Close()
			}
		} else {
			req := constructRequest("serviceinvocation-callee-0", "posthandler", "POST", jsonBody)
			_, err := daprClient.InvokeService(r.Context(), req)
			result.CallSuccessful = err == nil
		}

		results[i] = result
	}

	json.NewEncoder(w).Encode(results)
}

func doValidate(w http.ResponseWriter, r *http.Request) error {
	query := r.URL.Query()
	mainSpanName := query.Get("spanName")
	resp, err := http.Get(zipkinEndpoint + zipkinTraces)
	if err != nil {
		return err
	}

	defer resp.Body.Close()

	v := interface{}(nil)

	json.NewDecoder(resp.Body).Decode(&v)

	mainSpanID, err := findUniqueValueFromJSONPath("$..[?(@.name==\""+mainSpanName+"\")].id", v)
	if err != nil {
		return err
	}

	if mainSpanID == "" {
		return errors.New("empty span id found for span name " + mainSpanName)
	}
	log.Printf("Found main span with name %s and id=%s", mainSpanName, mainSpanID)

	childSpanName, err := findUniqueValueFromJSONPath("$..[?(@.parentId==\""+mainSpanID+"\")].name", v)
	if err != nil {
		return err
	}

	remoteServiceName, err := findUniqueValueFromJSONPath("$..[?(@.parentId==\""+mainSpanID+"\")].tags[\"net.peer.name\"]", v)
	if err != nil {
		return err
	}

	expectedDaprChildSpanName := fmt.Sprintf(expectedDaprChildSpanNameTemplate, remoteServiceName)
	if childSpanName != expectedDaprChildSpanName {
		return errors.New("child span name is not correct, expected " + expectedDaprChildSpanName + ", actual " + childSpanName)
	}

	for _, otelAttr := range otelRequiredAttributes {
		attrVal, err := findUniqueValueFromJSONPath("$..[?(@.parentId==\""+mainSpanID+"\")].tags[\""+otelAttr+"\"]", v)
		if err != nil {
			return err
		}

		if attrVal == "" {
			return errors.New("required span's tag not found: " + otelAttr)
		}
	}

	log.Printf("Tracing is correct for span with name=%s", mainSpanName)
	return nil
}

